#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
const int N = 500005;
struct Edge {
	int L, R, lz, Maxcover;
};
struct Line {
	int L, R, len;
};
Line li[N];
int n, m;
map < int, int > mp;
Edge tr[6 * N];
int C[4 * N];
int id[N];
int ans = 1e18;
int Left = 1, Right;
inline int read() {
    int x = 0, f = 1;
    char ch = getchar();
    while (ch < '0' || ch > '9') {
        if (ch == '-') f = -1;
        ch = getchar();
    }
    while (ch >= '0' && ch <= '9') {
        x = x * 10 + ch - '0';
        ch = getchar();
    }
    return x * f;
}
bool cmp(Line a, Line b) {
    return a.len < b.len;
}
void build (int p, int L, int R) {
	tr[p] = {L, R, 0, 0};
	if (L == R) {
		return;
	}
	int mid = (L + R) / 2;
	build (p << 1, L, mid);
	build (p << 1 | 1 , mid + 1, R);
	tr[p].Maxcover = max (tr[p << 1].Maxcover, tr[p << 1 | 1].Maxcover);
}
void uplz (int p,int lz) {
	tr[p].lz += lz;
	tr[p].Maxcover += lz;
}
void pushdown (int p) {
	if( tr[p].lz ) {
		uplz( p << 1 , tr[p].lz );
		uplz( ( p << 1 ) + 1 , tr[p].lz );
		tr[p].lz = 0;
	}
}
void modify (int p, int l, int r, int val) {
	if (tr[p].L > r || tr[p].R < l) {
		return;
	}
	if (tr[p].L >= l && tr[p].R <= r) {
		uplz (p, val);
		return;
	}
	pushdown (p);
	modify ((p << 1), l, r, val);
	modify ((p << 1 | 1), l, r, val);
	tr[p].Maxcover = max (tr[p << 1].Maxcover, tr[p << 1 | 1].Maxcover);
}
int query (int p, int a, int b) {
	if (tr[p].L > b || tr[p].R < a) {
		return (int)1e18;
	}
	if (tr[p].L >= a && tr[p].R <= b) {
		return tr[p].Maxcover;
	}
	pushdown (p);
	return max (query(p << 1, a, b), query(p << 1 | 1, a, b));
}
signed main() {
	ios::sync_with_stdio(false);
	cin.tie(nullptr), cout.tie(nullptr);
	n = read();
	m = read();
	for (int i = 1; i <= n; i++) {
        li[i].L = read();
        li[i].R = read();
        li[i].len = li[i].R - li[i].L;
        mp[li[i].L] = 1;
        mp[li[i].R] = 1;
    }
    int cnt = 0;
    for (auto &it : mp) {
        it.second = ++cnt;
    }
    for (int i = 1; i <= n; i++) {
        li[i].L = mp[li[i].L];
        li[i].R = mp[li[i].R];
    }
    sort(li + 1, li + n + 1, cmp);
    build (1, 1, cnt);
    while (Right <= n) {
        if (query(1, 1, cnt) < m || Left > Right) {
            Right++;
            if (Right > n) {
            	break;
			}
            modify (1, li[Right].L, li[Right].R, 1);
        }
        if (query (1, 1, cnt) == m) {
            while (query (1, 1, cnt) == m && Left <= Right) {
                modify (1, li[Left].L, li[Left].R, -1);
                Left++;
            }
            ans = min(ans, li[Right].len - li[Left - 1].len);
        }
    }
    if (ans == 1e18) {
    	cout << "-1";
	} else {
		cout << ans;
	}
	return 0;
}
